-- 211 - Dragon's Lair Normal wave composition + enemy stats (VERIFIED ground truth, 2026-07-23).
-- Supersedes seed 205 (whose affinity->stage assignment was scrambled). Source: in-game screenshots,
-- all 25 Normal stages, read by hand (Mike). Affinity is NOT stored: it derives from champion_id
-- (verified each mob''s canonical affinity == its stage wave affinity). CR/CD constant 15/50.
-- Requires migrations/2026-07-22_dungeon_stage_enemies_waves.sql.
delete from dungeon_stage_enemies where dungeon_id=(select id from dungeons where name='Dragon''s Lair' and game_id='raid_shadow_legends') and wave_number > 0;
insert into dungeon_stage_enemies
 (dungeon_id, stage_number, wave_number, position, enemy_name, enemy_role, champion_id, enemy_level, difficulty, hp, atk, def, spd, res, acc, crit_rate, crit_dmg, source_note, verified_at)
